<template>
    <div class="container-fluid">
      <div class="row">
          <div class="col-12 col-md-12">
              <div class="row">
                  <div class="col-12 m-3">
                      <h2>
                          <svg xmlns="http://www.w3.org/2000/svg" width="32" height="32" fill="currentColor" class="bi bi-pencil-fill" viewBox="0 0 16 16">
                              <path d="M12.854.146a.5.5 0 0 0-.707 0L10.5 1.793 14.207 5.5l1.647-1.646a.5.5 0 0 0 0-.708l-3-3zm.646 6.061L9.793 2.5 3.293 9H3.5a.5.5 0 0 1 .5.5v.5h.5a.5.5 0 0 1 .5.5v.5h.5a.5.5 0 0 1 .5.5v.5h.5a.5.5 0 0 1 .5.5v.207l6.5-6.5zm-7.468 7.468A.5.5 0 0 1 6 13.5V13h-.5a.5.5 0 0 1-.5-.5V12h-.5a.5.5 0 0 1-.5-.5V11h-.5a.5.5 0 0 1-.5-.5V10h-.5a.499.499 0 0 1-.175-.032l-.179.178a.5.5 0 0 0-.11.168l-2 5a.5.5 0 0 0 .65.65l5-2a.5.5 0 0 0 .168-.11l.178-.178z"/>
                          </svg>
                          編輯客戶
                      </h2>
                  </div>
              </div>
              <div>
                  <div class="mb-3">
                      <label for="newcustomerName" class="form-label">客戶名稱</label>
                      <input v-model="fullName" type="text" class="form-control" id="newcustomerName" required>
                  </div> 
                  <div class="mb-3">
                      <label for="customerDesc" class="form-label">客戶地址</label>
                      <input v-model="address" type="text" class="form-control" id="customerDesc">
                  </div> 
                  <div class="mb-3">
                      <label for="customerPrice" class="form-label">客戶生日</label>
                      <div class="col-sm-5 me-auto  ">
                        <input v-model="birth" class="w-100" type="date" id="datepicker" name="datepicker">
                      </div>
                    </div> 
                  <div class="mb-3">
                      <label for="customerStock" class="form-label">客戶Email</label>
                      <input  v-model="email" type="text" class="form-control" id="customerStock" required>
                  </div> 
                  <div class="mb-3">
                      <label for="category" class="form-label">客戶手機號碼</label>
                      <input v-model="phoneNumber" type="text" class="form-control" id="category" required>
                  </div> 
                  <div class="mb-3">
                      <label for="customerImg" class="form-label">最後登入日</label>
                      <input v-model="lastLoginDate" type="text" class="form-control" id="customerImg" disabled>
                  </div> 
              </div>
              <div class="row">
                  <div class="col-12 col-md-12">
                      <button id="submitBtn" @click="submitEditcustomer" class="btn btn-success w-100 mb-3">
                          <template v-if="!submiting">
                              <div>
                                  新增商品
                              </div>
                          </template>
                          <template v-if="submiting">
                              <div>
                                  <div class="spinner-border" role="status">
                                      <span class="visually-hidden">Loading...</span>
                                  </div>
                              </div>
                          </template>
                      </button>
                      <div v-if="isSubmitSuccess" class="alert alert-success text-center" role="alert">
                          顧客資訊更改完成！
                      </div>
                      <div v-if="submitFailed" class="alert alert-danger" role="alert">
                          顧客資訊更改失敗！請聯絡客服中心
                      </div>
                  </div>
              </div>
                  
          </div>
      </div>
    </div>
  </template>
  
  <script>
  import {toRefs,ref,toRaw,onMounted} from 'vue'
  import axios from 'axios'
  import { useBackendInfoTempStore } from '@/store/backendInfoTemp'
  import {useRouter} from 'vue-router'
  export default {
    name:'BackEndEditcustomer',
    setup(){
      let router =useRouter()
      let backendinfo =useBackendInfoTempStore()
      let submiting=ref(false)
      let submitFailed=ref(false)
      let isSubmitSuccess=ref(false)
      let customer = backendinfo.customer
  
  
      function submitEditcustomer(){
          submiting.value=true
          this.submitFailed=false
          for(let detail in customer){
             if(customer[detail]===''){
              this.submitFailed=true
              submiting.value=false
                 return
             }
          }
          
          
          
          axios.post('/updateuserinfo',toRaw(customer),{headers:{'contentType':'application/jason'}}).then(
              () => {
                  isSubmitSuccess.value=true
                  submiting.value=false
                  
              }
          )        
  
      }
      
  
     onMounted(()=>{
        for(let detail in customer){
          if(customer[detail]===''){
              router.push('/backenddashboard/customers')
          }
        }
     })
  
  
      return{
          ...toRefs(customer),
          isSubmitSuccess,
          submitEditcustomer,
          submiting,
          submitFailed
      }
      }
      
  }
  </script>
  
